/**
 * VerifyPhoto — 人脸验证页面
 * 用于完成 FaceVerify 任务（提现前必须通过）
 *
 * 流程：展示头像 → 可上传/裁剪新照片 → 点击 Verify →
 *   Web 端：后端获取 Token → 跳转旷视 H5 → 回跳 → 后端校验结果
 *   App 端：Bridge 调用原生 SDK → 后端校验结果（todo）
 * → 后端统一完成：活体/比对/颜值校验 + 标记 isFaceVerified
 */

import { useEffect } from "react";
import Layout from "@/components/Layout";
import NavigationBar from "@/components/NavigationBar";
import Button from "@/components/Button";
import CropPhotoModal from "@/components/CropPhotoModal";
import PhotoChangeModal from "@/components/PhotoChangeModal";
import SuccessCard from "./SuccessCard";
import { useVerifyPhoto } from "@/hooks/useVerifyPhoto";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

export default function VerifyPhoto() {
  const {
    imageSrc,
    imageFile,
    imgSize,
    showPhotoModal,
    showCropModal,
    showSuccessCard,
    isVerified,
    hasPickedNewPhoto,
    fileInputRef,
    imgRef,
    setShowPhotoModal,
    setShowCropModal,
    handleBack,
    handleImageLoad,
    handleFileChange,
    triggerFileInput,
    handleCropComplete,
    handleVerify,
    handleVerifySuccess,
  } = useVerifyPhoto();

  // 埋点：验证页面展示
  useEffect(() => {
    bpTrack(EventName.pwa_conv_verify_page_show);
    bpTrack(EventName.pwa_onboarding_verification_needed_for_cashout_toast_show);
    bpTrack(EventName.pwa_verify_photo_page_show);
  }, []);

  return (
    <Layout showTabBar={false}>
      <div className="flex flex-col h-full bg-surface">
        <NavigationBar title="Verify profile to Unlock Cashouts" onBack={handleBack} />

        <div className="flex-1 flex flex-col items-center justify-between px-6 pb-8">
          {/* 标题 */}
          <h2 className="mt-10 text-xl font-bold text-brand-dark text-center">Verify Profile Photo</h2>

          {/* 照片展示区 */}
          <div
            className="flex items-center justify-center w-[80vw] h-[80vw] max-w-[320px] max-h-[320px] overflow-hidden rounded-3xl border border-dashed border-[#6bc4ff] bg-[rgba(107,196,255,0.2)]"
            onClick={() => {
              if (!isVerified) {
                // 埋点：验证步骤点击（点击照片区域）
                bpTrack(EventName.pwa_conv_verify_step_click, {
                  step_type: "photo_area",
                });
                setShowPhotoModal(true);
              }
            }}
          >
            <img
              ref={imgRef}
              src={imageSrc}
              alt="Profile photo"
              className="w-full h-full object-cover"
              onLoad={handleImageLoad}
            />
          </div>

          {/* 隐藏的文件输入 */}
          <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />

          {/* 底部按钮 */}
          {isVerified ? (
            <div className="h-14" />
          ) : (
            <div className="flex flex-col items-center w-full gap-2">
              <Button onClick={handleVerify} variant="primary">
                {hasPickedNewPhoto ? "Save and Verify" : "Verify"}
              </Button>
              {!hasPickedNewPhoto && (
                <button
                  className="h-10 bg-transparent border-none text-[#159cd7] font-normal text-[15px]"
                  onClick={() => {
                    // 埋点：验证步骤点击（上传新照片按钮）
                    bpTrack(EventName.pwa_conv_verify_step_click, {
                      step_type: "upload_button",
                    });
                    setShowPhotoModal(true);
                  }}
                  type="button"
                >
                  Upload a New Photo
                </button>
              )}
            </div>
          )}
        </div>

        {/* 照片要求弹窗 */}
        <PhotoChangeModal
          open={showPhotoModal}
          onClose={() => setShowPhotoModal(false)}
          onChooseFromAlbum={() => triggerFileInput(false)}
          onTakePhoto={() => triggerFileInput(true)}
        />

        {/* 裁剪弹窗 */}
        {imageFile && (
          <CropPhotoModal
            open={showCropModal}
            onClose={() => setShowCropModal(false)}
            avatarUri={imageSrc}
            avatarFile={imageFile}
            onCropPhoto={handleCropComplete}
            initImgSize={imgSize}
          />
        )}

        {/* 成功弹窗 */}
        <SuccessCard open={showSuccessCard} onFinish={handleVerifySuccess} />
      </div>
    </Layout>
  );
}
